CREATE TABLE IF NOT EXISTS readings (station_id LowCardinality(String), source LowCardinality(String), parameter LowCardinality(String), ts DateTime('America/New_York'), value Float64) ENGINE = ReplacingMergeTree ORDER BY (station_id, parameter, ts);
CREATE TABLE IF NOT EXISTS predictions (station_id LowCardinality(String), kind LowCardinality(String), ts DateTime('America/New_York'), value Float64, extreme LowCardinality(String)) ENGINE = ReplacingMergeTree ORDER BY (station_id, kind, ts);
CREATE TABLE IF NOT EXISTS trips (trip_id UUID, user_id String, started_at DateTime('America/New_York'), route String, rating LowCardinality(String), notes String, created_at DateTime DEFAULT now()) ENGINE = MergeTree ORDER BY (user_id, started_at);
CREATE TABLE IF NOT EXISTS watches (watch_id UUID, user_id String, chat_id String, trip_time DateTime('America/New_York'), email String, status LowCardinality(String), created_at DateTime DEFAULT now()) ENGINE = ReplacingMergeTree(created_at) ORDER BY watch_id;
CREATE TABLE IF NOT EXISTS waypoints (waypoint_id LowCardinality(String), name String, lat Float64, lon Float64, kind LowCardinality(String), notes String) ENGINE = MergeTree ORDER BY waypoint_id;
